import json

threads = [
{"threadId": "150f0f6022c95f98", "messages": [
{"messageId": "150f0f6022c95f98", "headers": {"From": "'Nil Geisweiller' via opencog <opencog@googlegroups.com>", "Date": "Tue, 10 Nov 2015 12:34:27 +0200", "Subject": "[opencog-dev] Make atom C++ factory better"}, "body": "While debugging and navigating the AtomSpace code I wonder if we could simplify all that. What about we auto generate a C++ hierarchy of nodes and links following atom_types.script, filling the blanks with default constructors and keeping existing code in opencog/atoms. The auto generation script could also verify consistency with atom_types.script."},
{"messageId": "150f0f9d3d0fd303", "headers": {"From": "'Nil Geisweiller' via opencog <opencog@googlegroups.com>", "Date": "Tue, 10 Nov 2015 12:38:37 +0200", "Subject": "[opencog-dev] Re: Make atom C++ factory better"}, "body": "It would also make C++ hypergraph definition terser: ListLink(ConceptNode(\"A\"), PredicateNode(\"P\")) instead of as->add_link(...)"},
{"messageId": "150f842cef3b291b", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Wed, 11 Nov 2015 22:35:17 +0200", "Subject": "Re: [opencog-dev] Make atom C++ factory better"}, "body": "I don't think I really like that idea very much. It is a premature design optimization; the code is still very highly experimental, and I don't want to bake in what might be a bad design decision. Experimental: e.g. after discussions with Ben, its clear we should get rid of TV and AV. But how? I tried to create ProtoAtoms but there are implementation problems. Adding auto-generated code would make this harder. Its solving a non-problem. Its not like the current code is hard to maintain."},
{"messageId": "150f848c329be8f9", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Wed, 11 Nov 2015 22:41:47 +0200", "Subject": "Re: [opencog-dev] Re: Make atom C++ factory better"}, "body": "You can do this today with macros. Some unit test cases already do: #define AL as->add_link, #define AN as->add_node. With some template magic you could clean that up. But I discourage people from doing too much atomese in C++ anyway."}
]},
{"threadId": "150c26368a01877f", "messages": [
{"messageId": "150c26368a01877f", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Sun, 1 Nov 2015 18:31:45 +0900", "Subject": "Putting deep learning perception into OpenCog"}, "body": "Some general thoughts on the blog. A fairly specific design suggestion on the wiki page Deep Learning Perception in OpenCog."},
{"messageId": "150c6a11777a03f5", "headers": {"From": "'Nil Geisweiller' via hk-addis@opencog.org <hk-addis@opencog.org>", "Date": "Mon, 2 Nov 2015 07:18:07 +0200", "Subject": "Re: Putting deep learning perception into OpenCog"}, "body": "Although I can't comment on the specifics as I don't have much experience with deep learning, I think this is an excellent suggestion."},
{"messageId": "150c6e8f1e5e282d", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Mon, 2 Nov 2015 15:36:05 +0900", "Subject": "Re: Putting deep learning perception into OpenCog"}, "body": "I have been supervising students and some iCog staff experimenting with deep learning vision for a few years now, so I think I have a good sense of the area, although it hasn't been used in OpenCog yet..."},
{"messageId": "150c8c4aad899838", "headers": {"From": "Jim Rutt <jim@jimrutt.com>", "Date": "Mon, 2 Nov 2015 10:15:41 -0500", "Subject": "Re: [opencog-dev] Putting deep learning perception into OpenCog"}, "body": "Seems to me the Cognitive Synergy aspect would be if broad high level inferences and probabilities from the atomspace could be continuously feedback into the deep learning implementation. My suspicion is that it is coupled systems that operate at different levels of abstraction that will be the most fruitful."},
{"messageId": "150ca81370f82ff7", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Tue, 3 Nov 2015 08:21:14 +0900", "Subject": "Re: [opencog-dev] Putting deep learning perception into OpenCog"}, "body": "Yeah, that will be the big win from an AGI perspective. Along the way, we will also be creating the most flexible tool for building deep learning architectures out there."}
]},
{"threadId": "1507239a05c17b7f", "messages": [
{"messageId": "1507239a05c17b7f", "headers": {"From": "Jim Rutt <jimrutt@gmail.com>", "Date": "Fri, 16 Oct 2015 12:56:28 -0700", "Subject": "[opencog-dev] Deer Conscious Cognition Project: Unity, Opencog, ZeroMQ"}, "body": "I have completed the first prototype of my first non-toy Opencog project. The main purpose was to get basic plumbing in place to connect Unity3D and Opencog via ZeroMQ. I achieved very close to real time synchronization on a 40hz frame rate simulation, pushing about 200,000 messages per second. ZeroMQ is impressively fast."},
{"messageId": "1507280755aeb304", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Fri, 16 Oct 2015 17:13:51 -0400", "Subject": "Re: [opencog-dev] Deer Conscious Cognition Project"}, "body": "Thanks Jim -- Along with many other purposes, this may be useful as a playground for ECAN tweaking..."},
{"messageId": "150843153478390a", "headers": {"From": "'Nil Geisweiller' via opencog <opencog@googlegroups.com>", "Date": "Tue, 20 Oct 2015 10:40:33 +0300", "Subject": "Re: [opencog-dev] Deer Conscious Cognition Project"}, "body": "Wow, it is really cool to see you are moving forward with that project, Jim! Have you put the code online?"},
{"messageId": "15086e7cbb348f19", "headers": {"From": "Matt Chapman <matt@ninjitsuweb.com>", "Date": "Tue, 20 Oct 2015 13:18:48 -0700", "Subject": "Re: [opencog-dev] Deer Conscious Cognition Project"}, "body": "Really cool! Thanks for sharing. I am hoping to read your spec in full when I have time."},
{"messageId": "1508fbb2021ae2ee", "headers": {"From": "Jim Rutt <jimrutt@gmail.com>", "Date": "Thu, 22 Oct 2015 06:26:55 -0700", "Subject": "[opencog-dev] Re: Deer Conscious Cognition Project"}, "body": "I have uploaded the software for AIDeer as three github code repositories at github.com/memetic007. Warning: this code is rough prototype style code. I have long preferred building a throw away first prototype to achieve end-to-end connectivity and benchmark the couplings for performance."}
]}
]

for t in threads:
    with open("raw_data_exports/gmail_raw_2015/" + t["threadId"] + ".json", "w") as f:
        json.dump(t, f, indent=2)
    print("Saved " + t["threadId"])
